function convertToLocalTime(dateString: string, timeZone: string = 'Asia/Shanghai'): string {
    const date = new Date(dateString);

    const options: Intl.DateTimeFormatOptions = {
        timeZone: timeZone,
        year: 'numeric',
        month: '2-digit',
        day: '2-digit',
